+/**
+ * SMS notification adapter.
+ *
+ * Implements NotificationAdapter for the 'sms' channel. Handles phone number
+ * validation, message formatting, and SMS delivery. In production the
+ * transport layer would integrate with Twilio / AWS SNS / etc.; the
+ * adapter abstracts that behind a pluggable `SmsTransport` interface.
+ *
+ * ## Usage
+ * ```ts
+ * const smsAdapter = new SmsAdapter(eventBus);
+ * notificationService.registerAdapter(smsAdapter);
+ * ```
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationSendEvent } from '../events/event-types.js';
+import type {
+  NotificationChannel,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+import type { NotificationAdapter } from './notification.adapter.js';
+
+// ---------------------------------------------------------------------------
+// SMS transport abstraction
+// ---------------------------------------------------------------------------
+
+/** A rendered SMS ready for delivery. */
+export interface SmsMessage {
+  to: string;
+  body: string;
+}
+
+/**
+ * Pluggable transport that actually sends the SMS.
+ * Swap in a real Twilio/SNS implementation for production.
+ */
+export interface SmsTransport {
+  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
+}
+
+/**
+ * Default in-memory transport that records sent messages.
+ * Used in development / testing.
+ */
+export class InMemorySmsTransport implements SmsTransport {
+  private sent: SmsMessage[] = [];
+
+  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
+    const messageId = `sms-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
+    this.sent.push(message);
+    return { messageId };
+  }
+
+  getSentMessages(): SmsMessage[] {
+    return [...this.sent];
+  }
+
+  clear(): void {
+    this.sent = [];
+  }
+}
+
+// ---------------------------------------------------------------------------
+// Message formatting
+// ---------------------------------------------------------------------------
+
+/**
+ * Format a notification payload into an SMS message body.
+ * SMS messages are plain text with a subject prefix and truncated to
+ * 160 characters to fit a single SMS segment.
+ */
+export function formatSmsBody(payload: NotificationPayload): string {
+  const text = `${payload.subject}: ${payload.body}`;
+  if (text.length <= 160) {
+    return text;
+  }
+  return text.slice(0, 157) + '...';
+}
+
+// ---------------------------------------------------------------------------
+// Phone number validation
+// ---------------------------------------------------------------------------
+
+/** Matches E.164 format: +{country code}{number}, 8-15 digits total. */
+const PHONE_REGEX = /^\+[1-9]\d{7,14}$/;
+
+/**
+ * Validate and normalise a phone number.
+ * Strips spaces and dashes, then checks E.164 format.
+ * Returns the cleaned number or null if invalid.
+ */
+export function validatePhoneNumber(phone: string): string | null {
+  const cleaned = phone.replace(/[\s\-()]/g, '').trim();
+  if (!PHONE_REGEX.test(cleaned)) {
+    return null;
+  }
+  return cleaned;
+}
+
+// ---------------------------------------------------------------------------
+// SmsAdapter
+// ---------------------------------------------------------------------------
+
+export class SmsAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'sms';
+  private logger = new Logger('SmsAdapter');
+  private transport: SmsTransport;
+
+  /** Sent payloads — exposed for testing. */
+  private sent: NotificationPayload[] = [];
+
+  constructor(private eventBus: EventBus, transport?: SmsTransport) {
+    this.transport = transport ?? new InMemorySmsTransport();
+    this.registerHandler();
+  }
+
+  /**
+   * Subscribe to notification:send events and handle sms-channel payloads.
+   */
+  private registerHandler(): void {
+    this.eventBus.on<NotificationSendEvent>('notification:send', async (event) => {
+      if (event.payload.channel === this.channel) {
+        await this.send(event.payload);
+      }
+    });
+  }
+
+  /**
+   * Deliver an SMS notification.
+   *
+   * 1. Validate the recipient phone number.
+   * 2. Format the notification body for SMS.
+   * 3. Send via the configured SmsTransport.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      // 1. Phone number validation
+      const phone = validatePhoneNumber(payload.recipient);
+      if (!phone) {
+        const error = `Invalid phone number: ${payload.recipient}`;
+        this.logger.error(error);
+        return { success: false, error };
+      }
+
+      // 2. Format message
+      const body = formatSmsBody(payload);
+      const message: SmsMessage = { to: phone, body };
+
+      // 3. Send via transport
+      const result = await this.transport.sendSms(message);
+      this.logger.info(
+        `SMS sent to ${phone}: "${payload.subject}" [${result.messageId}]`,
+      );
+
+      this.sent.push(payload);
+      return { success: true };
+    } catch (err: unknown) {
+      const message = err instanceof Error ? err.message : 'Unknown SMS delivery error';
+      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
+      return { success: false, error: message };
+    }
+  }
+
+  /**
+   * Get all payloads that were successfully sent (useful for testing).
+   */
+  getSentSms(): NotificationPayload[] {
+    return [...this.sent];
+  }
+
+  /**
+   * Clear the sent SMS list (useful for testing).
+   */
+  clearSentSms(): void {
+    this.sent = [];
+  }
+
+  /**
+   * Get the underlying transport (useful for testing with InMemorySmsTransport).
+   */
+  getTransport(): SmsTransport {
+    return this.transport;
+  }
+}

