+      expect(transport.getSentMessages()).toHaveLength(1);
+    });
+
+    it('should ignore notification:send events for other channels', async () => {
+      await eventBus.emit({
+        type: 'notification:send',
+        payload: {
+          recipient: 'alice@example.com',
+          subject: 'Test',
+          body: 'Test body',
+          notificationType: 'order_confirmation' as const,
+          channel: 'email' as const,
+          priority: 'normal' as const,
+        },
+        timestamp: new Date(),
+      });
+
+      expect(adapter.getSentSms()).toHaveLength(0);
