+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Utility methods
+  // -------------------------------------------------------------------------
+
+  describe('utility methods', () => {
+    it('should clear sent SMS', async () => {
+      await adapter.send({
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Test',
+        notificationType: 'order_confirmation',
+        channel: 'sms',
+      });
+
+      adapter.clearSentSms();
+      expect(adapter.getSentSms()).toHaveLength(0);
+    });
+
+    it('should expose the transport', () => {
+      expect(adapter.getTransport()).toBe(transport);
+    });
+  });
+});

